object Solution { def unflatten_config(flat: Map[String, Any]): Map[String, Any] = { val root = scala.collection.mutable.Map[String, Any](); for ((path, value) <- flat) { val segments = path.split("\\."); var node = root; for (segment <- segments.dropRight(1)) { val next = node.getOrElseUpdate(segment, scala.collection.mutable.Map[String, Any]()).asInstanceOf[scala.collection.mutable.Map[String, Any]]; node = next }; node(segments.last) = value }; freeze(root) }; private def freeze(node: scala.collection.mutable.Map[String, Any]): Map[String, Any] = node.toMap.map { case (key, value) => key -> (value match { case child: scala.collection.mutable.Map[_, _] => freeze(child.asInstanceOf[scala.collection.mutable.Map[String, Any]]); case leaf => leaf }) } }
